class User(UserMixin, db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), unique=True, nullable=False, index=True)
    password_hash = db.Column(db.String(200), nullable=False)
    mfa_enabled = db.Column(db.Boolean, default=False)
    mfa_secret = db.Column(db.String(32), nullable=True)
    backup_codes = db.Column(db.Text, nullable=True)
    mfa_reset_token_hash = db.Column(db.String(64), nullable=True)
    mfa_reset_token_created = db.Column(db.DateTime, nullable=True)
    mfa_reset_used = db.Column(db.Boolean, default=False)
    failed_mfa_attempts = db.Column(db.Integer, default=0)
    last_failed_mfa = db.Column(db.DateTime, nullable=True)
    account_locked_until = db.Column(db.DateTime, nullable=True)

    def set_password(self, password):
        self.password_hash = generate_password_hash(password)

    def check_password(self, password):
        return check_password_hash(self.password_hash, password)

    def generate_mfa_secret(self):
        self.mfa_secret = pyotp.random_base32()
        return self.mfa_secret

    def get_totp_uri(self):
        return pyotp.totp.TOTP(self.mfa_secret).provisioning_uri(
            name=self.email,
            issuer_name='MFA System'
        )

    def verify_totp(self, token):
        if not self.mfa_secret:
            return False
        totp = pyotp.TOTP(self.mfa_secret)
        return totp.verify(token, valid_window=1)

    def generate_backup_codes(self):
        codes = [secrets.token_hex(4) for _ in range(10)]
        hashed_codes = [hashlib.sha256(code.encode()).hexdigest() for code in codes]
        self.backup_codes = ','.join(hashed_codes)
        return codes

    def verify_backup_code(self, code):
        if not self.backup_codes:
            return False
        code_hash = hashlib.sha256(code.encode()).hexdigest()
        codes = self.backup_codes.split(',')
        if code_hash in codes:
            codes.remove(code_hash)
            self.backup_codes = ','.join(codes)
            db.session.commit()
            return True
        return False

    def is_account_locked(self):
        if self.account_locked_until and datetime.utcnow() < self.account_locked_until:
            return True
        return False

    def record_failed_mfa(self):
        self.failed_mfa_attempts += 1
        self.last_failed_mfa = datetime.utcnow()
        if self.failed_mfa_attempts >= 5:
            self.account_locked_until = datetime.utcnow() + timedelta(minutes=30)
        db.session.commit()

    def reset_failed_mfa(self):
        self.failed_mfa_attempts = 0
        self.last_failed_mfa = None
        self.account_locked_until = None
        db.session.commit()


class MFAResetLog(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    user_id = db.Column(db.Integer, db.ForeignKey('user.id'), nullable=False)
    requested_at = db.Column(db.DateTime, default=datetime.utcnow)
    completed_at = db.Column(db.DateTime, nullable=True)
    ip_address = db.Column(db.String(45), nullable=True)
    user_agent = db.Column(db.String(200), nullable=True)
    status = db.Column(db.String(20), default='pending')


@login_manager.user_loader
def load_user(user_id):
    return User.query.get(int(user_id))


def send_email(to_email, subject, body):
    try:
        msg = MIMEMultipart('alternative')
        msg['Subject'] = subject
        msg['From'] = app.config['MAIL_FROM']
        msg['To'] = to_email

        html_part = MIMEText(body, 'html')
        msg.attach(html_part)

        with smtplib.SMTP(app.config['MAIL_SERVER'], app.config['MAIL_PORT']) as server:
            server.starttls()
            if app.config['MAIL_USERNAME'] and app.config['MAIL_PASSWORD']:
                server.login(app.config['MAIL_USERNAME'], app.config['MAIL_PASSWORD'])
            server.send_message(msg)
        return True
    except Exception as e:
        print(f"Email sending failed: {e}")
        return False


def require_mfa(f):
    @wraps(f)
    @login_required
    def decorated_function(*args, **kwargs):
        if current_user.mfa_enabled and not request.cookies.get('mfa_verified'):
            return jsonify({'error': 'MFA verification required'}), 403
        return f(*args, **kwargs)
    return decorated_function


def rate_limit_check(user):
    if user.is_account_locked():
        return False, 'Account temporarily locked due to multiple failed attempts'
    return True, None


@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    email = data.get('email', '').strip().lower()
    password = data.get('password', '')

    if not email or not password:
        return jsonify({'error': 'Email and password required'}), 400

    if User.query.filter_by(email=email).first():
        return jsonify({'error': 'Email already registered'}), 400

    user = User(email=email)
    user.set_password(password)
    db.session.add(user)
    db.session.commit()

    return jsonify({'message': 'User registered successfully', 'user_id': user.id}), 201


@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    email = data.get('email', '').strip().lower()
    password = data.get('password', '')
    mfa_token = data.get('mfa_token', '')

    user = User.query.filter_by(email=email).first()

    if not user or not user.check_password(password):
        return jsonify({'error': 'Invalid credentials'}), 401

    if user.is_account_locked():
        return jsonify({'error': 'Account temporarily locked. Please try again later.'}), 403

    if user.mfa_enabled:
        if not mfa_token:
            return jsonify({'message': 'MFA token required', 'mfa_required': True}), 200

        if not user.verify_totp(mfa_token) and not user.verify_backup_code(mfa_token):
            user.record_failed_mfa()
            return jsonify({'error': 'Invalid MFA token'}), 401

        user.reset_failed_mfa()

    login_user(user)
    response = jsonify({'message': 'Login successful', 'mfa_enabled': user.mfa_enabled})
    
    if user.mfa_enabled:
        response.set_cookie('mfa_verified', 'true', httponly=True, secure=True, samesite='Strict', max_age=3600)
    
    return response, 200


@app.route('/logout', methods=['POST'])
@login_required
def logout():
    logout_user()
    response = jsonify({'message': 'Logged out successfully'})
    response.set_cookie('mfa_verified', '', expires=0)
    return response, 200


@app.route('/mfa/setup', methods=['POST'])
@login_required
def setup_mfa():
    if current_user.mfa_enabled:
        return jsonify({'error': 'MFA already enabled'}), 400

    secret = current_user.generate_mfa_secret()
    db.session.commit()

    totp_uri = current_user.get_totp_uri()
    
    qr = qrcode.QRCode(version=1, box_size=10, border=5)
    qr.add_data(totp_uri)
    qr.make(fit=True)
    img = qr.make_image(fill_color="black", back_color="white")
    
    buf = io.BytesIO()
    img.save(buf, format='PNG')
    buf.seek(0)
    qr_code_base64 = base64.b64encode(buf.getvalue()).decode()

    return jsonify({
        'secret': secret,
        'qr_code': f'data:image/png;base64,{qr_code_base64}',
        'totp_uri': totp_uri
    }), 200


@app.route('/mfa/enable', methods=['POST'])
@login_required
def enable_mfa():
    data = request.get_json()
    token = data.get('token', '')

    if not current_user.mfa_secret:
        return jsonify({'error': 'MFA not set up. Call /mfa/setup first'}), 400

    if not current_user.verify_totp(token):
        return jsonify({'error': 'Invalid token'}), 401

    current_user.mfa_enabled = True
    backup_codes = current_user.generate_backup_codes()
    db.session.commit()

    return jsonify({
        'message': 'MFA enabled successfully',
        'backup_codes': backup_codes
    }), 200


@app.route('/mfa/disable', methods=['POST'])
@require_mfa
def disable_mfa():
    data = request.get_json()
    password = data.get('password', '')
    token = data.get('token', '')

    if not current_user.check_password(password):
        return jsonify({'error': 'Invalid password'}), 401

    if not current_user.verify_totp(token) and not current_user.verify_backup_code(token):
        return jsonify({'error': 'Invalid MFA token'}), 401

    current_user.mfa_enabled = False
